VALUES ('Clopidogrel', (SELECT id FROM pgx_drug_classes WHERE code='cardio' LIMIT 1), 'Plavix®, Clopiplax®, Cuore®, Dogrelix®, Plaq®, Plaquevix®', 'O clopidogrel é um antiplaquetário PRÓ-DROGA que PRECISA ser ativado pelo CYP2C19. Em metabolizadores lentos (*2/*2), é INEFICAZ. Em metabolizadores RÁPIDOS (*17), a eficácia é AUMENTADA (mais metabólito ativo). O CPIC recomenda ticagrelor/prasugrel para metabolizadores lentos.', 'CYP2C19 *1/*17 (CT) = METABOLIZADOR RÁPIDO. Para clopidogrel, isso é FAVORÁVEL — mais metabólito ativo é produzido, com eficácia antiplaquetária AUMENTADA. CES1 (TT) = normal.', 'rs12248560', '10', 'CYP2C19', 'Europeia', 'CYP2C19 e Clopidogrel (CPIC):\n- *1/*1 = Normal (eficácia adequada)\n- *1/*17 = Metabolizador rápido → EFICÁCIA AUMENTADA (boa notícia!)\n- *17/*17 = Ultra-rápido → Eficácia ainda maior\n- *1/*2 = Intermediário → Eficácia reduzida (considerar alternativa)\n- *2/*2 = Lento → INEFICAZ (usar ticagrelor)', 'CYP2C19 *1/*17 é FAVORÁVEL para clopidogrel (diferente dos IBPs!). O clopidogrel funciona BEM neste paciente — a ativação é AUMENTADA. Se antiplaquetário for necessário, clopidogrel é opção adequada (não precisa de ticagrelor por motivo genético, embora ticagrelor funcione independente do CYP2C19).', 'Nunca inicie, interrompa ou altere tratamentos sem orientação médica.', 1) ON DUPLICATE KEY UPDATE class_id=VALUES(class_id), commercial_names=VALUES(commercial_names), description=VALUES(description), understanding_result=VALUES(understanding_result), snp_rsid=VALUES(snp_rsid), chromosome=VALUES(chromosome), gene_symbol=VALUES(gene_symbol), study_population=VALUES(study_population), genotype_results=VALUES(genotype_results), suggestions=VALUES(suggestions), disclaimer=VALUES(disclaimer), updated_at=NOW();

VALUES ('Clobazam', (SELECT id FROM pgx_drug_classes WHERE code='psiq_neuro' LIMIT 1), 'Frisium®, Onfi®, Sympazan®', 'O clobazam é um benzodiazepínico 1,5- utilizado como anticonvulsivante adjuvante (epilepsia) e ansiolítico. É metabolizado pelo CYP2C19 em N-desmetilclobazam (metabólito ativo). O CPIC tem guideline: em metabolizadores lentos, o metabólito ACUMULA com mais sedação.', 'CYP2C19 *1/*17 (CT) = METABOLIZADOR RÁPIDO. O clobazam e seu metabólito ativo podem ser eliminados mais rapidamente, com duração potencialmente MENOR do efeito anticonvulsivante.', 'rs12248560', '10', 'CYP2C19', 'Europeia', 'CYP2C19 e Clobazam (CPIC):\n- *1/*1 = Normal\n- *1/*17 = Rápido (duração pode ser menor)\n- *2/*2 = Lento (metabólito ACUMULA - sedação excessiva)', 'CYP2C19 *1/*17. Clobazam pode ter duração MENOR. Se usado como anticonvulsivante, monitorar controle de crises. Pode necessitar ajuste de dose ou frequência. Para ansiedade, considerar lorazepam (não depende CYP) como alternativa.', 'Nunca inicie, interrompa ou altere tratamentos sem orientação médica.', 1) ON DUPLICATE KEY UPDATE class_id=VALUES(class_id), commercial_names=VALUES(commercial_names), description=VALUES(description), understanding_result=VALUES(understanding_result), snp_rsid=VALUES(snp_rsid), chromosome=VALUES(chromosome), gene_symbol=VALUES(gene_symbol), study_population=VALUES(study_population), genotype_results=VALUES(genotype_results), suggestions=VALUES(suggestions), disclaimer=VALUES(disclaimer), updated_at=NOW();

VALUES ('Ciclosporina', (SELECT id FROM pgx_drug_classes WHERE code='imuno_transplante' LIMIT 1), 'Sandimmun®, Restasis®', 'A ciclosporina é um imunossupressor inibidor da calcineurina utilizado para transplantes e doenças autoimunes. É metabolizada pelo CYP3A4/CYP3A5. Em expressores do CYP3A5, metabolismo aumentado com necessidade de dose maior (similar ao tacrolimo).', 'CYP3A5 (rs776746 CT) = EXPRESSOR PARCIAL. A ciclosporina pode ser eliminada mais rapidamente, necessitando dose potencialmente MAIOR (similar ao tacrolimo). TDM obrigatório.', 'rs776746', '7', 'CYP3A5', 'Europeia', 'CYP3A5 rs776746 e Ciclosporina:\n- GG/AA (não-expressor) = Dose padrão\n- CT/AG (expressor parcial) = Pode necessitar dose maior\n- CC/TT (expressor) = Dose significativamente maior\n\nTDM obrigatório.', 'CYP3A5 expressor parcial (CT). Ciclosporina pode necessitar dose MAIOR (similar ao tacrolimo). Monitoramento de níveis séricos (TDM) é OBRIGATÓRIO. Achado consistente com o do tacrolimo.', 'Nunca inicie, interrompa ou altere tratamentos sem orientação médica.', 1) ON DUPLICATE KEY UPDATE class_id=VALUES(class_id), commercial_names=VALUES(commercial_names), description=VALUES(description), understanding_result=VALUES(understanding_result), snp_rsid=VALUES(snp_rsid), chromosome=VALUES(chromosome), gene_symbol=VALUES(gene_symbol), study_population=VALUES(study_population), genotype_results=VALUES(genotype_results), suggestions=VALUES(suggestions), disclaimer=VALUES(disclaimer), updated_at=NOW();

VALUES ('Cetamina', (SELECT id FROM pgx_drug_classes WHERE code='psiq_neuro' LIMIT 1), 'Ketalar®, Cetamin®, Ketamin-S®', 'A cetamina é um anestésico dissociativo utilizado para anestesia, dor crônica e depressão resistente (infusão IV/intranasal Spravato). É metabolizada pelo CYP2B6 em norketamina. NÃO depende do CYP2D6. Efeitos adversos incluem dissociação, alucinações, náuseas, hipertensão e potencial de abuso.', 'CYP2B6 (rs3211371) N/D. A cetamina NÃO depende do CYP2D6 nem CYP2C19 — é uma opção com MENOS incerteza farmacogenética para este paciente.', 'rs3211371', '19', 'CYP2B6', 'Europeia', 'CYP2B6: N/D\n\nNota: Cetamina NÃO depende de CYP2D6, CYP2C19 nem CYP3A4.', 'RELEVANTE PARA CIRURGIA + DEPRESSÃO RESISTENTE: CYP2B6 indeterminado mas cetamina tem MENOS dependência dos CYP450 conhecidos. Para anestesia na cirurgia maxilar, pode ser usada como adjuvante (efeito analgésico + dissociativo). Para depressão resistente (off